### 简要说明
这是一个交互式3D DNA双螺旋结构模型，还原了DNA的核心结构特征：反向平行的脱氧核糖磷酸骨架、遵循互补配对规则的碱基对、右手螺旋构型。你可以拖动鼠标旋转视角、滚轮缩放来观察细节，点击结构部件可查看详细功能说明。

```show-widget
{"title": "dna_double_helix_3d", "widget_code": "<style>
canvas { display: block; width: 100% !important; height: 420px !important; }
#controls { display: flex; align-items: center; gap: 12px; padding: 10px 0 0; font-size: 13px; color: var(--color-text-secondary); }
.legend { display: flex; flex-wrap: wrap; gap: 16px; font-size: 12px; color: var(--color-text-secondary); }
.legend span { display: flex; align-items: center; gap: 4px; }
.legend .dot { width: 10px; height: 10px; border-radius: 50%; }
</style>
<canvas id="c"></canvas>
<div id="controls">
  <div class="legend">
    <span><span class="dot" style="background:#7F77DD;"></span>磷酸骨架</span>
    <span><span class="dot" style="background:#ED93B1;"></span>腺嘌呤(A)</span>
    <span><span class="dot" style="background:#F0997B;"></span>胸腺嘧啶(T)</span>
    <span><span class="dot" style="background:#378ADD;"></span>鸟嘌呤(G)</span>
    <span><span class="dot" style="background:#639922;"></span>胞嘧啶(C)</span>
  </div>
</div>
<script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
<script src="https://cdn.jsdelivr.net/npm/three@0.128.0/examples/js/controls/OrbitControls.js" onload="init()"></script>
<script>
var scene, camera, renderer, controls;
var clickTargets = [];
function init() {
  if (!window.THREE || !THREE.OrbitControls) return;
  var canvas = document.getElementById('c');
  var W = canvas.clientWidth, H = 420;
  renderer = new THREE.WebGLRenderer({ canvas: canvas, antialias: true, alpha: true });
  renderer.setSize(W, H);
  renderer.setPixelRatio(Math.min(devicePixelRatio, 2));

  scene = new THREE.Scene();
  camera = new THREE.PerspectiveCamera(45, W / H, 0.1, 1000);
  camera.position.set(0, 5, 12);

  scene.add(new THREE.AmbientLight(0xffffff, 0.6));
  var sun = new THREE.DirectionalLight(0xffffff, 0.9);
  sun.position.set(5, 8, 5);
  scene.add(sun);

  controls = new THREE.OrbitControls(camera, canvas);
  controls.enableDamping = true;
  controls.dampingFactor = 0.08;
  controls.autoRotate = true;
  controls.autoRotateSpeed = 0.5;

  // 生成DNA结构
  const basePairs = 12;
  const radius = 2;
  const risePerStep = 0.5;
  const anglePerStep = 36 * Math.PI / 180;

  const backboneMat = new THREE.MeshLambertMaterial({ color: 0x7F77DD });
  const aMat = new THREE.MeshLambertMaterial({ color: 0xED93B1 });
  const tMat = new THREE.MeshLambertMaterial({ color: 0xF0997B });
  const gMat = new THREE.MeshLambertMaterial({ color: 0x378ADD });
  const cMat = new THREE.MeshLambertMaterial({ color: 0x639922 });
  const bondMat = new THREE.MeshLambertMaterial({ color: 0x888780 });

  for (let i = 0; i < basePairs; i++) {
    const angle = i * anglePerStep;
    const y = i * risePerStep - (basePairs * risePerStep)/2;

    // 骨架1
    const x1 = Math.cos(angle) * radius;
    const z1 = Math.sin(angle) * radius;
    const backbone1 = new THREE.Mesh(new THREE.SphereGeometry(0.18, 12, 8), backboneMat);
    backbone1.position.set(x1, y, z1);
    backbone1.name = '磷酸骨架';
    scene.add(backbone1);
    clickTargets.push(backbone1);

    // 骨架2
    const x2 = Math.cos(angle + Math.PI) * radius;
    const z2 = Math.sin(angle + Math.PI) * radius;
    const backbone2 = new THREE.Mesh(new THREE.SphereGeometry(0.18, 12, 8), backboneMat);
    backbone2.position.set(x2, y, z2);
    backbone2.name = '磷酸骨架';
    scene.add(backbone2);
    clickTargets.push(backbone2);

    // 碱基对连接
    const bond = new THREE.Mesh(new THREE.CylinderGeometry(0.05, 0.05, radius * 2 - 0.4, 8), bondMat);
    bond.position.set((x1 + x2)/2, y, (z1 + z2)/2);
    bond.lookAt(x2, y, z2);
    bond.rotateX(Math.PI/2);
    scene.add(bond);

    // 碱基配对，交替AT和GC
    if (i % 2 === 0) {
      // A-T配对
      const a = new THREE.Mesh(new THREE.SphereGeometry(0.15, 10, 8), aMat);
      a.position.set(x1 * 0.8, y, z1 * 0.8);
      a.name = 'A-T碱基对';
      scene.add(a);
      clickTargets.push(a);

      const t = new THREE.Mesh(new THREE.SphereGeometry(0.15, 10, 8), tMat);
      t.position.set(x2 * 0.8, y, z2 * 0.8);
      t.name = 'A-T碱基对';
      scene.add(t);
      clickTargets.push(t);
    } else {
      // G-C配对
      const g = new THREE.Mesh(new THREE.SphereGeometry(0.15, 10, 8), gMat);
      g.position.set(x1 * 0.8, y, z1 * 0.8);
      g.name = 'G-C碱基对';
      scene.add(g);
      clickTargets.push(g);

      const c = new THREE.Mesh(new THREE.SphereGeometry(0.15, 10, 8), cMat);
      c.position.set(x2 * 0.8, y, z2 * 0.8);
      c.name = 'G-C碱基对';
      scene.add(c);
      clickTargets.push(c);
    }
  }

  // 点击检测
  const raycaster = new THREE.Raycaster();
  const mouse = new THREE.Vector2();
  let dragDist = 0, startX, startY;
  canvas.addEventListener('mousedown', e => { startX = e.clientX; startY = e.clientY; dragDist = 0; });
  canvas.addEventListener('mousemove', e => { dragDist += Math.abs(e.clientX - startX) + Math.abs(e.clientY - startY); });
  canvas.addEventListener('click', e => {
    if (dragDist > 5) return;
    const rect = canvas.getBoundingClientRect();
    mouse.x = ((e.clientX - rect.left) / rect.width) * 2 - 1;
    mouse.y = -((e.clientY - rect.top) / rect.height) * 2 + 1;
    raycaster.setFromCamera(mouse, camera);
    const hits = raycaster.intersectObjects(clickTargets);
    if (hits.length) {
      const name = hits[0].object.name;
      if (name === '磷酸骨架') window.__widgetSendMessage('详细介绍DNA的磷酸骨架结构和功能');
      if (name === 'A-T碱基对') window.__widgetSendMessage('详细介绍A-T碱基配对规则和特性');
      if (name === 'G-C碱基对') window.__widgetSendMessage('详细介绍G-C碱基配对规则和特性');
    }
  });

  function animate() {
    requestAnimationFrame(animate);
    controls.update();
    renderer.render(scene, camera);
  }
  animate();
}
if (window.THREE && THREE.OrbitControls) init();
</script>"}
```

### 补充说明
1. 模型中紫色球体代表脱氧核糖磷酸骨架，是双螺旋的外侧结构，为DNA提供了稳定的分子骨架
2. 内侧的彩色球体代表四种碱基：腺嘌呤(A，粉色)、胸腺嘧啶(T，珊瑚色)、鸟嘌呤(G，蓝色)、胞嘧啶(C，绿色)，严格遵循A-T配对、G-C配对的互补规则
3. 每一圈螺旋包含约10对碱基，相邻碱基对的垂直距离为0.34纳米，螺距为3.4纳米，与真实DNA的物理参数一致

你可以点击对应的结构部件，获取更详细的生物学特性和功能说明。
